import { GoldRushClient } from "@covalenthq/client-sdk";

const client = new GoldRushClient(process.env.GOLDRUSH_API_KEY);

async function monitorBridgeSecurity(chainName, bridgeContract) {
  const events = await client.BaseService.getLogEventsByAddress(
    chainName, bridgeContract, { startingBlock: "latest" }
  );
  const withdrawals = (events.data?.items ?? []).filter(
    e => e.decoded?.name === "TokensReleased" || e.decoded?.name === "Withdraw"
  );
  const largeWithdrawals = withdrawals.filter(e => {
    const amount = Number(e.decoded?.params?.find(p => p.name === "amount")?.value ?? 0);
    return amount > 1e21;
  });
  return { bridgeContract, totalWithdrawals: withdrawals.length, largeWithdrawals: largeWithdrawals.length };
}
